1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const CURSE_SURCHARGE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const COMPONENT_BASE_PREMIUM = 25;
12	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
13	const COMPONENT_BLOCK_SIZE = 3;
14	
15	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	};
19	
20	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
21	
22	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
23	
24	const mainItemPremium = (item: Item): number => {
25	  const base = MAIN_ITEM_BASE_PREMIUM[item.type];
26	  const curse = item.cursed ? base * CURSE_SURCHARGE : 0;
27	  const highEnchantment =
28	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE : 0;
29	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
30	  return base + curse + highEnchantment + firstInsurance;
31	};
32	
33	const componentGroupBase = (count: number): number => {
34	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
35	  const leftover = count % COMPONENT_BLOCK_SIZE;
36	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
37	};
38	
39	const componentCountsByType = (components: Item[]): Map<string, number> => {
40	  const counts = new Map<string, number>();
41	  for (const item of components) {
42	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  }
44	  return counts;
45	};
46	
47	const sumComponentPremiums = (components: Item[]): number =>
48	  [...componentCountsByType(components).values()].reduce(
49	    (total, count) => total + componentGroupBase(count) * (1 + FIRST_INSURANCE_SURCHARGE),
50	    0,
51	  );
52	
53	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
54	  const mainItems: Item[] = [];
55	  const components: Item[] = [];
56	  for (const item of items) {
57	    (isMainItem(item) ? mainItems : components).push(item);
58	  }
59	  return { mainItems, components };
60	};
61	
62	const sumMainItemPremiums = (mainItems: Item[]): number =>
63	  mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
64	
65	const sumItemPremiums = (items: Item[]): number => {
66	  const { mainItems, components } = partitionItems(items);
67	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
68	};
69	
70	const priceQuote = (step: QuoteStep): { premium: number } => ({
71	  premium: ceilWithEpsilon(sumItemPremiums(step.items) + PROCESSING_FEE),
72	});
73	
74	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
75	  results: scenario.steps.map(priceQuote),
76	});
